#!/bin/bash
GREEN='\033[0;32m'; BLUE='\033[0;34m'; YELLOW='\033[1;33m'; NC='\033[0m'
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
FE="$SCRIPT_DIR/Beme-Frontend"
echo ""
echo -e "${BLUE}Beme — Nav Redesign + Chat Fix${NC}"
echo ""
echo -e "${YELLOW}[1/5] BottomNav.jsx${NC}"
echo "" | base64 -d > "$FE/src/components/navigation/BottomNav.jsx"
echo -e "  ${GREEN}✓${NC} BottomNav.jsx"
echo -e "${YELLOW}[2/5] BottomNav.css${NC}"
echo "" | base64 -d > "$FE/src/components/navigation/BottomNav.css"
echo -e "  ${GREEN}✓${NC} BottomNav.css"
echo -e "${YELLOW}[3/5] StoreFront.jsx${NC}"
echo "" | base64 -d > "$FE/src/pages/StoreFront.jsx"
echo -e "  ${GREEN}✓${NC} StoreFront.jsx"
echo -e "${YELLOW}[4/5] Header.jsx — Messages link${NC}"
python3 - << 'PYEOF2'
import os
hdr = os.environ.get("SCRIPT_DIR","") + "/Beme-Frontend/src/components/Header.jsx"
try:
    with open(hdr,"r",encoding="utf-8") as f: h=f.read()
    if "SetIconMessages" not in h:
        h=h.replace("function SetIconLogout() {",'''function SetIconMessages() {
  return (<svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>);
}
function SetIconLogout() {''')
    if '"/messages"' not in h:
        old='''onClick={() => settingsNav("/orders")} type="button">
          <span className="hdr-set-item-icon"><SetIconOrders /></span>Orders
        </button>
        <hr className="hdr-set-divider"'''
        new='''onClick={() => settingsNav("/orders")} type="button">
          <span className="hdr-set-item-icon"><SetIconOrders /></span>Orders
        </button>
        <button className="hdr-set-item" onClick={() => settingsNav("/messages")} type="button">
          <span className="hdr-set-item-icon"><SetIconMessages /></span>Messages
        </button>
        <hr className="hdr-set-divider"'''
        h=h.replace(old,new)
    with open(hdr,"w",encoding="utf-8") as f: f.write(h)
    print("  patched ok")
except Exception as e: print(f"  warn: {e}")
PYEOF2
echo -e "  ${GREEN}✓${NC} Header.jsx"
echo -e "${YELLOW}[5/5] Header.css — flat dropdown (no dividers)${NC}"
python3 - << 'PYEOF3'
import os
css_path = os.environ.get("SCRIPT_DIR","") + "/Beme-Frontend/src/components/Header.css"
try:
    with open(css_path,"r",encoding="utf-8") as f: c=f.read()
    c=c.replace(
        "  border-bottom: 1px solid var(--border);
  cursor: pointer;
  font-size: 13px;
  font-weight: 500;
  font-family: var(--font-main);
  color: var(--text);
  text-align: left;
  transition: background 100ms ease, color 100ms ease;",
        "  cursor: pointer;
  font-size: 13px;
  font-weight: 500;
  font-family: var(--font-main);
  color: var(--text);
  text-align: left;
  transition: background 100ms ease, color 100ms ease;"
    )
    c=c.replace(".hdr-set-item:last-of-type { border-bottom: none; }
","")
    with open(css_path,"w",encoding="utf-8") as f: f.write(c)
    print("  patched ok")
except Exception as e: print(f"  warn: {e}")
PYEOF3
echo -e "  ${GREEN}✓${NC} Header.css"
echo ""
echo -e "${YELLOW}Manual — ProductDetails.jsx (3 changes):${NC}"
echo -e "  Remove: const [showChat, setShowChat] = useState(false);"
echo -e "  Change: onClick={() => navigate(\`/messages?seller=\${sellerId || shop2.ownerId}\`)}"
echo -e "  Remove: {showChat && <ChatModal shop={shop2} onClose={...} />}"
echo ""
echo -e "${GREEN}✓ Done! Deploy: cd Beme-Frontend && git add . && git commit -m \"Nav redesign\" && git push${NC}"